import os
import json
import hashlib
from pathlib import Path
from typing import Optional

import numpy as np
from openai import OpenAI

# ---------------------------------------------------------------------------
# Configuration
# ---------------------------------------------------------------------------

OPENAI_API_KEY = os.getenv("OPENAI_API_KEY", "your-openai-api-key-here")
EMBEDDING_MODEL = "text-embedding-3-small"
CHAT_MODEL = "gpt-4o-mini"
CHUNK_SIZE = 500          # characters per chunk
CHUNK_OVERLAP = 100       # overlap between chunks
TOP_K = 5                 # number of chunks to retrieve
VECTOR_DB_PATH = "vector_store.json"

client = OpenAI(api_key=OPENAI_API_KEY)


# ---------------------------------------------------------------------------
# Simple Vector Database (file-backed, no external DB dependency)
# ---------------------------------------------------------------------------

class VectorStore:
    """A minimal vector store backed by a JSON file and numpy cosine search."""

    def __init__(self, path: str = VECTOR_DB_PATH):
        self.path = path
        self.documents: list[dict] = []   # {id, text, embedding, metadata}
        self._load()

    # -- persistence ---------------------------------------------------------

    def _load(self):
        if os.path.exists(self.path):
            with open(self.path, "r", encoding="utf-8") as f:
                self.documents = json.load(f)
            print(f"[VectorStore] Loaded {len(self.documents)} chunks from {self.path}")
        else:
            self.documents = []

    def _save(self):
        with open(self.path, "w", encoding="utf-8") as f:
            json.dump(self.documents, f)
        print(f"[VectorStore] Saved {len(self.documents)} chunks to {self.path}")

    # -- core operations -----------------------------------------------------

    def add(self, text: str, embedding: list[float], metadata: dict | None = None):
        doc_id = hashlib.sha256(text.encode()).hexdigest()[:16]
        # skip duplicates
        if any(d["id"] == doc_id for d in self.documents):
            return
        self.documents.append({
            "id": doc_id,
            "text": text,
            "embedding": embedding,
            "metadata": metadata or {},
        })

    def search(self, query_embedding: list[float], top_k: int = TOP_K) -> list[dict]:
        if not self.documents:
            return []

        q = np.array(query_embedding)
        scored = []
        for doc in self.documents:
            d = np.array(doc["embedding"])
            # cosine similarity
            sim = float(np.dot(q, d) / (np.linalg.norm(q) * np.linalg.norm(d) + 1e-10))
            scored.append((sim, doc))

        scored.sort(key=lambda x: x[0], reverse=True)
        return [
            {"score": round(s, 4), "text": d["text"], "metadata": d["metadata"]}
            for s, d in scored[:top_k]
        ]

    def clear(self):
        self.documents = []
        if os.path.exists(self.path):
            os.remove(self.path)

    @property
    def size(self) -> int:
        return len(self.documents)


# ---------------------------------------------------------------------------
# Text processing helpers
# ---------------------------------------------------------------------------

def chunk_text(text: str, chunk_size: int = CHUNK_SIZE, overlap: int = CHUNK_OVERLAP) -> list[str]:
    """Split text into overlapping chunks."""
    chunks = []
    start = 0
    while start < len(text):
        end = start + chunk_size
        chunk = text[start:end].strip()
        if chunk:
            chunks.append(chunk)
        start += chunk_size - overlap
    return chunks


def read_file(filepath: str) -> str:
    """Read a text/markdown/json file and return its content as a string."""
    path = Path(filepath)
    suffix = path.suffix.lower()

    if suffix == ".json":
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return json.dumps(data, indent=2)
    else:
        # .txt, .md, .csv, .py, .html, etc.
        with open(path, "r", encoding="utf-8") as f:
            return f.read()


# ---------------------------------------------------------------------------
# Embedding helper
# ---------------------------------------------------------------------------

def get_embedding(text: str) -> list[float]:
    """Get an embedding vector from OpenAI."""
    response = client.embeddings.create(
        model=EMBEDDING_MODEL,
        input=text,
    )
    return response.data[0].embedding


def get_embeddings_batch(texts: list[str]) -> list[list[float]]:
    """Get embeddings for a batch of texts (max 2048 per call)."""
    all_embeddings: list[list[float]] = []
    batch_size = 2048
    for i in range(0, len(texts), batch_size):
        batch = texts[i : i + batch_size]
        response = client.embeddings.create(
            model=EMBEDDING_MODEL,
            input=batch,
        )
        all_embeddings.extend([d.embedding for d in response.data])
    return all_embeddings


# ---------------------------------------------------------------------------
# Document ingestion
# ---------------------------------------------------------------------------

def ingest_text(store: VectorStore, text: str, source: str = "unknown"):
    """Chunk a raw text string and add to the vector store."""
    chunks = chunk_text(text)
    if not chunks:
        print(f"[Ingest] No chunks produced from source '{source}'")
        return

    print(f"[Ingest] Embedding {len(chunks)} chunks from '{source}' ...")
    embeddings = get_embeddings_batch(chunks)

    for chunk, emb in zip(chunks, embeddings):
        store.add(text=chunk, embedding=emb, metadata={"source": source})

    store._save()
    print(f"[Ingest] Done. Store now has {store.size} chunks.")


def ingest_file(store: VectorStore, filepath: str):
    """Read a file, chunk it, embed it, and store it."""
    print(f"[Ingest] Reading file: {filepath}")
    text = read_file(filepath)
    ingest_text(store, text, source=filepath)


def ingest_directory(store: VectorStore, directory: str, extensions: tuple = (".txt", ".md", ".json", ".csv", ".py", ".html")):
    """Recursively ingest all matching files in a directory."""
    dir_path = Path(directory)
    if not dir_path.is_dir():
        print(f"[Ingest] Directory not found: {directory}")
        return

    files = [f for f in dir_path.rglob("*") if f.is_file() and f.suffix.lower() in extensions]
    print(f"[Ingest] Found {len(files)} files in '{directory}'")
    for fp in sorted(files):
        ingest_file(store, str(fp))


# ---------------------------------------------------------------------------
# Retrieval
# ---------------------------------------------------------------------------

def retrieve(store: VectorStore, query: str, top_k: int = TOP_K) -> list[dict]:
    """Embed the query and retrieve the most relevant chunks."""
    query_emb = get_embedding(query)
    results = store.search(query_emb, top_k=top_k)
    return results


# ---------------------------------------------------------------------------
# Prompt construction & LLM call
# ---------------------------------------------------------------------------

SYSTEM_PROMPT = """You are an internal knowledge-base assistant for our company.
Answer the user's question using ONLY the context provided below.
If the context does not contain enough information, say so honestly.
Always cite the source document when possible.

--- RETRIEVED CONTEXT ---
{context}
--- END CONTEXT ---"""


def build_context_block(results: list[dict]) -> str:
    """Format retrieved chunks into a single context string."""
    parts = []
    for i, r in enumerate(results, 1):
        source = r["metadata"].get("source", "unknown")
        parts.append(f"[Document {i} | source: {source} | relevance: {r['score']}]\n{r['text']}\n")
    return "\n".join(parts)


def ask(store: VectorStore, question: str, top_k: int = TOP_K, verbose: bool = False) -> str:
    """End-to-end RAG: retrieve context then generate an answer."""
    # 1. Retrieve
    results = retrieve(store, question, top_k=top_k)

    if verbose:
        print(f"\n{'='*60}")
        print(f"Query: {question}")
        print(f"Retrieved {len(results)} chunks:")
        for r in results:
            print(f"  - score={r['score']}  source={r['metadata'].get('source')}")
        print(f"{'='*60}\n")

    if not results:
        return "I couldn't find any relevant information in the knowledge base."

    # 2. Build prompt
    context_block = build_context_block(results)
    system_message = SYSTEM_PROMPT.format(context=context_block)

    # 3. Call LLM
    response = client.chat.completions.create(
        model=CHAT_MODEL,
        messages=[
            {"role": "system", "content": system_message},
            {"role": "user", "content": question},
        ],
        temperature=0.2,
        max_tokens=1024,
    )

    return response.choices[0].message.content


# ---------------------------------------------------------------------------
# Interactive chat loop
# ---------------------------------------------------------------------------

def chat_loop(store: VectorStore):
    """Run an interactive Q&A session."""
    print("\n" + "=" * 60)
    print("  Internal Knowledge Base Chatbot (RAG)")
    print("  Type 'quit' to exit, 'stats' for store info")
    print("=" * 60 + "\n")

    while True:
        try:
            user_input = input("You: ").strip()
        except (EOFError, KeyboardInterrupt):
            print("\nGoodbye!")
            break

        if not user_input:
            continue
        if user_input.lower() in ("quit", "exit", "q"):
            print("Goodbye!")
            break
        if user_input.lower() == "stats":
            print(f"[Store] {store.size} chunks indexed.")
            continue

        answer = ask(store, user_input, verbose=True)
        print(f"\nAssistant: {answer}\n")


